opR.dispatchEvent(new Event('input'));

/* ===== GRID INPUTS / DONE / CANCEL ===== */
$('dsaSkGRows').addEventListener('input',e=>{
  const v=Math.max(1,Math.min(50,+e.target.value||1));
  if(G.current)G.current.rows=v;
});
$('dsaSkGCols').addEventListener('input',e=>{
  const v=Math.max(1,Math.min(50,+e.target.value||1));
  if(G.current)G.current.cols=v;
});
$('dsaSkGridDone').addEventListener('click',(e)=>{e.stopPropagation();gridDone();});
$('dsaSkGridRemove').addEventListener('click',(e)=>{e.stopPropagation();gridRemove();});

/* ===== HEADER BUTTONS ===== */
$('dsaSkUndoBtn').addEventListener('click',undo);
$('dsaSkRedoBtn').addEventListener('click',redoFn);

$('dsaSkClearBtn').addEventListener('click',()=>{
  if(confirm('Clear canvas?')){
    ctx.save();ctx.setTransform(1,0,0,1,0,0);
    ctx.clearRect(0,0,cv.width,cv.height);
    ctx.restore();
    G.current=null;
    T.list=[];T.selected=null;T.editing=null;
    txEditor.style.display='none';
    saveH();
    toast('Canvas cleared');
  }
});

/* ===== DONE button — hook for your DB save ===== */
function exportCanvas(){
  const tmp=document.createElement('canvas');
  tmp.width=cv.width;tmp.height=cv.height;
  const tctx=tmp.getContext('2d');
  tctx.drawImage(cv,0,0);
  tctx.scale(DPR,DPR);
  for(const tb of T.list){
    tctx.fillStyle=tb.color;
    tctx.globalAlpha=tb.opacity;
    tctx.font=`600 ${tb.size}px -apple-system,sans-serif`;
    tctx.textBaseline='top';
    const lines=tb.text.split('\n');
    let yy=tb.y;
    for(const line of lines){tctx.fillText(line,tb.x,yy);yy+=tb.size*1.2;}
  }
  return tmp.toDataURL('image/png');
}
function flushSketchDone(){
  if(T.editing!==null)commitTextEdit();
  if(G.current)gridDone();
  syncInk();
  onChange();
  if(typeof hooks.onPersist==='function'){hooks.onPersist();}
  toast('Saved');
}
$('dsaSkDoneBtn').addEventListener('click',()=>{flushSketchDone();});

/* ===== IMAGE IMPORT ===== */
$('dsaSkImgInput').addEventListener('change',e=>{
  const f=e.target.files[0];
  if(!f)return;
  const r=new FileReader();
  r.onload=ev=>{
    const img=new Image();
    img.onload=()=>{
      const cssW=cv.width/DPR,cssH=cv.height/DPR;
      const sc=Math.min(cssW/img.width,cssH/img.height)*0.9;
      const w=img.width*sc,h=img.height*sc;
      ctx.drawImage(img,(cssW-w)/2,(cssH-h)/2,w,h);
      saveHNotify();
      toast('Image imported');
    };
    img.src=ev.target.result;
  };
  r.readAsDataURL(f);
  e.target.value='';
});

